52	/* Unpack argument object with named arguments into actual parameters. */
53	static pdf_js *unpack_arguments(js_State *J, ...)
54	{
55		if (js_isobject(J, 1))
56		{
57			int i = 1;
58			va_list args;
59	
60			js_copy(J, 1);
61	
62			va_start(args, J);
63			for (;;)
64			{
65				const char *s = va_arg(args, const char *);
66				if (!s)
67					break;
68				js_getproperty(J, -1, s);
69				js_replace(J, i++);
70			}
71			va_end(args);
72	
73			js_pop(J, 1);
74		}
75		return js_getcontext(J);
76	}
