78	static void app_alert(js_State *J)
79	{
80		pdf_js *js = unpack_arguments(J, "cMsg", "nIcon", "nType", "cTitle", "oDoc", "oCheckbox", NULL);
81		pdf_alert_event evt;
82	
83		/* TODO: Currently we do not support app.openDoc() in javascript actions, hence
84		oDoc can only point to the current document (or not be passed). When mupdf
85		supports opening other documents oDoc must be converted to a pdf_document * that
86		can be passed to the callback. In the mean time, we just pas the current document.
87		*/
88		evt.doc = js->doc;
89	
90		evt.message = js_tostring(J, 1);
91		evt.icon_type = js_tointeger(J, 2);
92		evt.button_group_type = js_tointeger(J, 3);
93		evt.title = js_isdefined(J, 4) ? js_tostring(J, 4) : "PDF alert";
94	
95		evt.has_check_box = 0;
96		evt.check_box_message = NULL;
97		evt.initially_checked = 0;
98		evt.finally_checked = 0;
99	
100		if (js_isobject(J, 6))
101		{
102			evt.has_check_box = 1;
103			evt.check_box_message = "Do not show this message again";
104			if (js_hasproperty(J, 6, "cMsg"))
105			{
106				if (js_iscoercible(J, -1))
107					evt.check_box_message = js_tostring(J, -1);
108				js_pop(J, 1);
109			}
110			if (js_hasproperty(J, 6, "bInitialValue"))
111			{
112				evt.initially_checked = js_tointeger(J, -1);
113				js_pop(J, 1);
114			}
115			if (js_hasproperty(J, 6, "bAfterValue"))
116			{
117				evt.finally_checked = js_tointeger(J, -1);
118				js_pop(J, 1);
119			}
120		}
121	
122		/* These are the default buttons automagically "pressed"
123		when the dialog box window is closed in Acrobat. */
124		switch (evt.button_group_type)
125		{
126		default:
127		case PDF_ALERT_BUTTON_GROUP_OK:
128			evt.button_pressed = PDF_ALERT_BUTTON_OK;
129			break;
130		case PDF_ALERT_BUTTON_GROUP_OK_CANCEL:
131			evt.button_pressed = PDF_ALERT_BUTTON_CANCEL;
132			break;
133		case PDF_ALERT_BUTTON_GROUP_YES_NO:
134			evt.button_pressed = PDF_ALERT_BUTTON_YES;
135			break;
136		case PDF_ALERT_BUTTON_GROUP_YES_NO_CANCEL:
137			evt.button_pressed = PDF_ALERT_BUTTON_CANCEL;
138			break;
139		}
140	
141		fz_try(js->ctx)
142			pdf_event_issue_alert(js->ctx, js->doc, &evt);
143		fz_catch(js->ctx)
144			rethrow(js);
145	
146		if (js_isobject(J, 6))
147		{
148			js_pushboolean(js->imp, evt.finally_checked);
149			js_setproperty(js->imp, 6, "bAfterValue");
150		}
151	
152		js_pushnumber(J, evt.button_pressed);
153	}
