241	static pdf_obj *load_color(pdf_js *js, int idx)
242	{
243		fz_context *ctx = js->ctx;
244		pdf_document *doc = js->doc;
245		js_State *J = js->imp;
246	
247		pdf_obj *color = NULL;
248		int i, n;
249		float c;
250	
251		n = js_getlength(J, idx);
252	
253		/* The only legitimate color expressed as an array of length 1
254		 * is [T], meaning transparent. Return a NULL object to represent
255		 * transparent */
256		if (n <= 1)
257			return NULL;
258	
259		fz_var(color);
260	
261		fz_try(ctx)
262		{
263			color = pdf_new_array(ctx, doc, n-1);
264			for (i = 0; i < n-1; i++)
265			{
266				js_getindex(J, idx, i+1);
267				c = js_tonumber(J, -1);
268				js_pop(J, 1);
269	
270				pdf_array_push_real(ctx, color, c);
271			}
272		}
273		fz_catch(ctx)
274		{
275			pdf_drop_obj(ctx, color);
276			rethrow(js);
277		}
278	
279		return color;
280	}
