520	static void doc_resetForm(js_State *J)
521	{
522		pdf_js *js = js_getcontext(J);
523		pdf_obj *field, *form;
524		fz_context *ctx = js->ctx;
525		int i, n;
526	
527		fz_try(ctx)
528			form = pdf_dict_getl(ctx, pdf_trailer(ctx, js->doc), PDF_NAME(Root), PDF_NAME(AcroForm), PDF_NAME(Fields), NULL);
529		fz_catch(ctx)
530			rethrow(js);
531	
532		/* An array of fields has been passed in. Call pdf_reset_field on each item. */
533		if (js_isarray(J, 1))
534		{
535			n = js_getlength(J, 1);
536			for (i = 0; i < n; ++i)
537			{
538				js_getindex(J, 1, i);
539				fz_try(ctx)
540					field = pdf_lookup_field(ctx, form, js_tostring(J, -1));
541				fz_catch(ctx)
542					rethrow(js);
543				if (field)
544					pdf_field_reset(ctx, js->doc, field);
545				js_pop(J, 1);
546			}
