640	static void util_printf_d(fz_context *ctx, fz_buffer *out, int ds, int sign, int pad, unsigned int w, int base, int value)
641	{
642		static const char *digits = "0123456789abcdef";
643		char buf[50];
644		unsigned int a, i;
645		int m = 0;
646	
647		if (w > sizeof buf)
648			w = sizeof buf;
649	
650		if (value < 0)
651		{
652			sign = '-';
653			a = -(unsigned)value; // cast to avoid UB on -INT_MIN
654		}
655		else
656		{
657			a = value;
658		}
659	
660		i = 0;
661		do
662		{
663			buf[i++] = digits[a % base];
664			a /= base;
665			if (a > 0 && ++m == 3)
666			{
667				if (ds == 0) buf[i++] = ',';
668				if (ds == 2) buf[i++] = '.';
669				m = 0;
670			}
671		} while (a);
672	
673		if (sign && w)
674		{
675			if (pad == '0')
676				while (i < w - 1)
677					buf[i++] = pad;
678			buf[i++] = sign;
679		}
680		while (i < w)
681			buf[i++] = pad;
682	
683		while (i > 0)
684			fz_append_byte(ctx, out, buf[--i]);
685	}
686	
687	static void util_printf_f(fz_context *ctx, fz_buffer *out, int ds, int sign, int pad, int special, unsigned int w, int p, double value)
688	{
689		char buf[40], *point, *digits = buf;
690		size_t n = 0;
691		int m = 0;
692	
693		fz_snprintf(buf, sizeof buf, "%.*f", p, value);
694	
695		if (*digits == '-')
696		{
697			sign = '-';
698			++digits;
699		}
700	
701		if (*digits != '.' && (*digits < '0' || *digits > '9'))
702		{
703			fz_append_string(ctx, out, "nan");
704			return;
705		}
706	
707		n = strlen(digits);
708		if (sign)
709			++n;
710		point = strchr(digits, '.');
711		if (point)
712			m = 3 - (point - digits) % 3;
713		else
714		{
715			m = 3 - n % 3;
716			if (special)
717				++n;
718		}
719		if (m == 3)
720			m = 0;
721	
722		if (pad == '0' && sign)
723			fz_append_byte(ctx, out, sign);
724		for (; n < w; ++n)
725			fz_append_byte(ctx, out, pad);
726		if (pad == ' ' && sign)
727			fz_append_byte(ctx, out, sign);
728	
729		while (*digits && *digits != '.')
730		{
731			fz_append_byte(ctx, out, *digits++);
732			if (++m == 3 && *digits && *digits != '.')
733			{
734				if (ds == 0) fz_append_byte(ctx, out, ',');
735				if (ds == 2) fz_append_byte(ctx, out, '.');
736				m = 0;
737			}
738		}
739	
740		if (*digits == '.' || special)
741		{
742			if (ds == 0 || ds == 1)
743				fz_append_byte(ctx, out, '.');
744			else
745				fz_append_byte(ctx, out, ',');
746		}
747	
748		if (*digits == '.')
749		{
750			++digits;
751			while (*digits)
752				fz_append_byte(ctx, out, *digits++);
753		}
754	}
