756	static void util_printf(js_State *J)
757	{
758		pdf_js *js = js_getcontext(J);
759		fz_context *ctx = js->ctx;
760		const char *fmt = js_tostring(J, 1);
761		fz_buffer *out = NULL;
762		int ds, p, sign, pad, special;
763		unsigned int w;
764		int c, i = 1;
765		int failed = 0;
766		const char *str;
767	
768		fz_var(out);
769		fz_try(ctx)
770		{
771			out = fz_new_buffer(ctx, 256);
772	
773			while ((c = *fmt++) != 0)
774			{
775				if (c == '%')
776				{
777					c = *fmt++;
778	
779					ds = 1;
780					if (c == ',')
781					{
782						c = *fmt++;
783						if (!c)
784							break;
785						ds = c - '0';
786					}
787	
788					special = 0;
789					sign = 0;
790					pad = ' ';
791					while (c == ' ' || c == '+' || c == '0' || c == '#')
792					{
793						if (c == '+') sign = '+';
794						else if (c == ' ') sign = ' ';
795						else if (c == '0') pad = '0';
796						else if (c == '#') special = 1;
797						c = *fmt++;
798					}
799					if (!pad)
800						pad = ' ';
801					if (!c)
802						break;
803	
804					w = 0;
805					while (c >= '0' && c <= '9')
806					{
807						w = w * 10 + (c - '0');
808						c = *fmt++;
809					}
810					if (w < 0)
811						w = 0;
812					if (!c)
813						break;
814	
815					p = 0;
816					if (c == '.')
817					{
818						c = *fmt++;
819						while (c >= '0' && c <= '9')
820						{
821							p = p * 10 + (c - '0');
822							c = *fmt++;
823						}
824						if (p < 0)
825							p = 0;
826					}
827					else
828					{
829						special = 1;
830					}
831					if (!c)
832						break;
833	
834					switch (c)
835					{
836					case '%':
837						fz_append_byte(ctx, out, '%');
838						break;
839					case 'x':
840						util_printf_d(ctx, out, ds, sign, pad, w, 16, js_tryinteger(J, ++i, 0));
841						break;
842					case 'd':
843						util_printf_d(ctx, out, ds, sign, pad, w, 10, js_tryinteger(J, ++i, 0));
844						break;
845					case 'f':
846						util_printf_f(ctx, out, ds, sign, pad, special, w, p, js_trynumber(J, ++i, 0));
847						break;
848					case 's':
849					default:
850						fz_append_string(ctx, out, js_trystring(J, ++i, ""));
851					}
852				}
853				else
854				{
855					fz_append_byte(ctx, out, c);
856				}
857			}
858	
859			str = fz_string_from_buffer(ctx, out);
860			if (js_try(J))
861			{
862				failed = 1;
863			}
864			else
865			{
866				js_pushstring(J, str);
867				js_endtry(J);
868			}
869		}
870		fz_always(ctx)
871			fz_drop_buffer(ctx, out);
872		fz_catch(ctx)
873			rethrow(js);
874	
875		if (failed)
876			js_throw(J);
877	}
