924		{
925	#ifdef _WIN32
926			js_pushstring(J, "WIN");
927	#elif defined(__APPLE__)
928			js_pushstring(J, "MAC");
929	#else
930			js_pushstring(J, "UNIX");
931	#endif
932			js_defproperty(J, -2, "app.platform", JS_READONLY | JS_DONTENUM | JS_DONTCONF);
933	
934			addmethod(J, "app.alert", app_alert, 6);
935			addmethod(J, "app.execMenuItem", app_execMenuItem, 1);
936			addmethod(J, "app.launchURL", app_launchURL, 2);
937		}
938		js_defglobal(J, "app", JS_READONLY | JS_DONTCONF | JS_DONTENUM);
939	
940		/* Create the Field prototype object */
941		js_newobject(J);
942		{
943			addproperty(J, "Field.value", field_getValue, field_setValue);
944			addproperty(J, "Field.type", field_getType, field_setType);
945			addproperty(J, "Field.borderStyle", field_getBorderStyle, field_setBorderStyle);
946			addproperty(J, "Field.textColor", field_getTextColor, field_setTextColor);
