957			addmethod(J, "console.println", console_println, 1);
958			addmethod(J, "console.clear", console_clear, 0);
959			addmethod(J, "console.show", console_show, 0);
960			addmethod(J, "console.hide", console_hide, 0);
961		}
962		js_defglobal(J, "console", JS_READONLY | JS_DONTCONF | JS_DONTENUM);
963	
964		/* Put all of the Doc methods in the global object, which is used as
965		 * the 'this' binding for regular non-strict function calls. */
966		js_pushglobal(J);
967		{
968			addproperty(J, "Doc.numPages", doc_getNumPages, doc_setNumPages);
969			addproperty(J, "Doc.author", doc_getAuthor, doc_setAuthor);
970			addproperty(J, "Doc.title", doc_getTitle, doc_setTitle);
971			addproperty(J, "Doc.subject", doc_getSubject, doc_setSubject);
972			addproperty(J, "Doc.keywords", doc_getKeywords, doc_setKeywords);
973			addproperty(J, "Doc.creator", doc_getCreator, doc_setCreator);
974			addproperty(J, "Doc.producer", doc_getProducer, doc_setProducer);
975			addproperty(J, "Doc.creationDate", doc_getCreationDate, doc_setCreationDate);
976			addproperty(J, "Doc.modDate", doc_getModDate, doc_setModDate);
977			addmethod(J, "Doc.getField", doc_getField, 1);
978			addmethod(J, "Doc.resetForm", doc_resetForm, 0);
979			addmethod(J, "Doc.calculateNow", doc_calculateNow, 0);
980			addmethod(J, "Doc.print", doc_print, 0);
981			addmethod(J, "Doc.mailDoc", doc_mailDoc, 6);
982		}
983		js_pop(J, 1);
984	
985		js_endtry(J);
986	
987		return 0;
988	}
