990	static int preload_helpers(pdf_js *js)
991	{
992		if (js_try(js->imp))
993			return -1;
994	
995		/* When testing on the cluster:
996		 * Use a fixed date for "new Date" and Date.now().
997		 * Sadly, this breaks uses of the Date function without the new keyword.
998		 * Return a fixed random sequence from Math.random().
999		 */
1000	#ifdef CLUSTER
1001		js_dostring(js->imp,
1002	"var MuPDFOldDate = Date\n"
1003	"Date = function() { return new MuPDFOldDate(298252800000); }\n"
1004	"Date.now = function() { return 298252800000; }\n"
1005	"Date.UTC = function() { return 298252800000; }\n"
1006	"Date.parse = MuPDFOldDate.parse;\n"
1007	"Math.random = function() { return (Math.random.seed = Math.random.seed * 48271 % 2147483647) / 2147483647; }\n"
1008	"Math.random.seed = 217;\n"
1009		);
1010	#endif
1011	
1012		js_dostring(js->imp,
1013	#include "js/util.js.h"
1014		);
1015	
1016		js_endtry(js->imp);
1017		return 0;
1018	}
