1056	static pdf_js *pdf_new_js(fz_context *ctx, pdf_document *doc)
1057	{
1058		pdf_js *js = fz_malloc_struct(ctx, pdf_js);
1059	
1060		js->ctx = ctx;
1061		js->doc = doc;
1062	
1063		fz_try(ctx)
1064		{
1065			/* Initialise the javascript engine, passing the fz_context for use in memory allocation. */
1066			js->imp = js_newstate(pdf_js_alloc, ctx, 0);
1067			if (!js->imp)
1068				fz_throw(ctx, FZ_ERROR_LIBRARY, "cannot initialize javascript engine");
1069	
1070			/* Also set our pdf_js context, so we can retrieve it in callbacks. */
1071			js_setcontext(js->imp, js);
1072	
1073			js->console = &default_js_console;
1074			js->console_user = js->ctx;
1075	
1076			if (declare_dom(js))
1077				fz_throw(ctx, FZ_ERROR_LIBRARY, "cannot initialize dom interface");
1078			if (preload_helpers(js))
1079				fz_throw(ctx, FZ_ERROR_LIBRARY, "cannot initialize helper functions");
1080		}
1081		fz_catch(ctx)
1082		{
1083			pdf_drop_js(ctx, js);
1084			fz_rethrow(ctx);
1085		}
1086	
1087		return js;
1088	}
