1090	static void pdf_js_load_document_level(pdf_js *js)
1091	{
1092		fz_context *ctx = js->ctx;
1093		pdf_document *doc = js->doc;
1094		pdf_obj *javascript;
1095		int len, i;
1096		int in_op = 0;
1097	
1098		javascript = pdf_load_name_tree(ctx, doc, PDF_NAME(JavaScript));
1099		len = pdf_dict_len(ctx, javascript);
1100	
1101		fz_var(in_op);
1102	
1103		fz_try(ctx)
1104		{
1105			pdf_begin_operation(ctx, doc, "Document level Javascript");
1106			in_op = 1;
1107			for (i = 0; i < len; i++)
1108			{
1109				pdf_obj *fragment = pdf_dict_get_val(ctx, javascript, i);
1110				pdf_obj *code = pdf_dict_get(ctx, fragment, PDF_NAME(JS));
1111				char *codebuf = pdf_load_stream_or_string_as_utf8(ctx, code);
1112				char buf[100];
1113				if (pdf_is_indirect(ctx, code))
1114					fz_snprintf(buf, sizeof buf, "%d", pdf_to_num(ctx, code));
1115				else
1116					fz_snprintf(buf, sizeof buf, "Root/Names/JavaScript/Names/%d/JS", (i+1)*2);
1117				pdf_js_execute(js, buf, codebuf, NULL);
1118				fz_free(ctx, codebuf);
1119			}
1120			pdf_end_operation(ctx, doc);
1121		}
1122		fz_always(ctx)
1123			pdf_drop_obj(ctx, javascript);
1124		fz_catch(ctx)
1125		{
1126			if (in_op)
1127				pdf_abandon_operation(ctx, doc);
1128			fz_rethrow(ctx);
1129		}
1130	}
