1175			js_getproperty(js->imp, -1, "rc");
1176			rc = js_tryboolean(js->imp, -1, 1);
1177			js_pop(js->imp, 1);
1178			if (rc)
1179			{
1180				js_getproperty(js->imp, -1, "value");
1181				*newtext = fz_strdup(js->ctx, js_trystring(js->imp, -1, ""));
1182				js_pop(js->imp, 1);
1183			}
1184			js_pop(js->imp, 1);
1185		}
1186		return rc;
1187	}
1188	
1189	void pdf_js_event_init_keystroke(pdf_js *js, pdf_obj *target, pdf_keystroke_event *evt)
1190	{
1191		if (js)
1192		{
1193			pdf_js_event_init(js, target, evt->value, evt->willCommit);
1194			js_getglobal(js->imp, "event");
1195			{
1196				js_pushstring(js->imp, evt->change);
1197				js_setproperty(js->imp, -2, "change");
1198				js_pushnumber(js->imp, evt->selStart);
1199				js_setproperty(js->imp, -2, "selStart");
1200				js_pushnumber(js->imp, evt->selEnd);
1201				js_setproperty(js->imp, -2, "selEnd");
1202			}
1203			js_pop(js->imp, 1);
1204		}
1205	}
1206	
1207	int pdf_js_event_result_keystroke(pdf_js *js, pdf_keystroke_event *evt)
1208	{
1209		int rc = 1;
1210		if (js)
1211		{
1212			js_getglobal(js->imp, "event");
1213			{
1214				js_getproperty(js->imp, -1, "rc");
1215				rc = js_tryboolean(js->imp, -1, 1);
1216				js_pop(js->imp, 1);
1217				if (rc)
1218				{
1219					js_getproperty(js->imp, -1, "change");
1220					evt->newChange = fz_strdup(js->ctx, js_trystring(js->imp, -1, ""));
1221					js_pop(js->imp, 1);
1222					js_getproperty(js->imp, -1, "value");
1223					evt->newValue = fz_strdup(js->ctx, js_trystring(js->imp, -1, ""));
1224					js_pop(js->imp, 1);
1225					js_getproperty(js->imp, -1, "selStart");
1226					evt->selStart = js_tryinteger(js->imp, -1, 0);
1227					js_pop(js->imp, 1);
1228					js_getproperty(js->imp, -1, "selEnd");
1229					evt->selEnd = js_tryinteger(js->imp, -1, 0);
1230					js_pop(js->imp, 1);
1231				}
1232			}
1233			js_pop(js->imp, 1);
1234		}
1235		return rc;
1236	}
1237	
1238	char *pdf_js_event_value(pdf_js *js)
1239	{
1240		char *value = NULL;
1241		if (js)
1242		{
1243			js_getglobal(js->imp, "event");
1244			js_getproperty(js->imp, -1, "value");
1245			value = fz_strdup(js->ctx, js_trystring(js->imp, -1, "undefined"));
1246			js_pop(js->imp, 2);
1247		}
1248		return value;
1249	}
1250	
1251	void pdf_js_execute(pdf_js *js, const char *name, const char *source, char **result)
1252	{
1253		fz_context *ctx;
1254		js_State *J;
1255	
1256		if (!js)
1257			return;
1258	
1259		ctx = js->ctx;
1260		J = js->imp;
1261	
1262		pdf_begin_implicit_operation(ctx, js->doc);
1263		fz_try(ctx)
1264		{
1265			if (js_ploadstring(J, name, source)) {
1266				if (result)
1267					*result = fz_strdup(ctx, js_trystring(J, -1, "Error"));
1268				js_pop(J, 1);
1269			} else {
1270				js_pushundefined(J);
1271				js_setlimit(J, PDF_JS_LIMIT_RUNTIME, PDF_JS_LIMIT_MEMORY);
1272				if (js_pcall(J, 0)) {
1273					if (result)
1274						*result = fz_strdup(ctx, js_trystring(J, -1, "Error"));
1275					else
1276						fz_write_printf(ctx, fz_stddbg(ctx), "js: %s\n", js_trystring(J, -1, "Error"));
1277					js_pop(J, 1);
1278				} else {
1279					if (result)
1280						*result = fz_strdup(ctx, js_tryrepr(J, -1, "can't convert to string"));
1281					js_pop(J, 1);
1282				}
1283			}
1284			pdf_end_operation(ctx, js->doc);
1285		}
1286		fz_catch(ctx)
1287		{
1288			pdf_abandon_operation(ctx, js->doc);
1289			fz_rethrow(ctx);
1290		}
1291	}
1292	
1293	pdf_js_console *pdf_js_get_console(fz_context *ctx, pdf_document *doc)
1294	{
1295		return (doc && doc->js) ? doc->js->console : NULL;
1296	}
1297	
1298	void pdf_js_set_console(fz_context *ctx, pdf_document *doc, pdf_js_console *console, void *user)
1299	{
1300		if (doc->js)
1301		{
1302			if (doc->js->console && doc->js->console->drop)
1303				doc->js->console->drop(doc->js->console, doc->js->console_user);
1304	
1305			doc->js->console = console;
1306			doc->js->console_user = user;
1307		}
1308	}
1309	
1310	void pdf_enable_js(fz_context *ctx, pdf_document *doc)
1311	{
1312		if (!doc->js)
1313		{
1314			doc->js = pdf_new_js(ctx, doc);
1315			pdf_js_load_document_level(doc->js);
1316		}
1317	}
1318	
1319	void pdf_disable_js(fz_context *ctx, pdf_document *doc)
1320	{
1321		pdf_drop_js(ctx, doc->js);
1322		doc->js = NULL;
1323	}
1324	
1325	int pdf_js_supported(fz_context *ctx, pdf_document *doc)
1326	{
1327		return doc->js != NULL;
1328	}
1329	
1330	#else /* FZ_ENABLE_JS */
1331	
1332	void pdf_drop_js(fz_context *ctx, pdf_js *js) { }
1333	void pdf_enable_js(fz_context *ctx, pdf_document *doc) { }
1334	void pdf_disable_js(fz_context *ctx, pdf_document *doc) { }
1335	int pdf_js_supported(fz_context *ctx, pdf_document *doc) { return 0; }
1336	void pdf_js_event_init(pdf_js *js, pdf_obj *target, const char *value, int willCommit) { }
1337	void pdf_js_event_init_keystroke(pdf_js *js, pdf_obj *target, pdf_keystroke_event *evt) { }
1338	int pdf_js_event_result_keystroke(pdf_js *js, pdf_keystroke_event *evt) { return 1; }
1339	int pdf_js_event_result(pdf_js *js) { return 1; }
1340	char *pdf_js_event_value(pdf_js *js) { return ""; }
1341	void pdf_js_execute(pdf_js *js, const char *name, const char *source, char **result) { }
1342	int pdf_js_event_result_validate(pdf_js *js, char **newvalue) { *newvalue=NULL; return 1; }
1343	pdf_js_console *pdf_js_get_console(fz_context *ctx, pdf_document *doc) { return NULL; }
1344	void pdf_js_set_console(fz_context *ctx, pdf_document *doc, pdf_js_console *console, void *user) { }
1345	
1346	
