625	pdf_update_page(fz_context *ctx, pdf_page *page)
626	{
627		pdf_annot *annot;
628		pdf_annot *widget;
629		int changed = 0;
630	
631		if (page->doc == NULL)
632			return 0;
633	
634		if (!page->doc->resynth_required && !page->doc->recalculate)
635			return 0;
636	
637		fz_try(ctx)
638		{
639			pdf_begin_implicit_operation(ctx, page->doc);
640	
641			if (page->doc->recalculate)
642				pdf_calculate_form(ctx, page->doc);
643	
644			for (annot = page->annots; annot; annot = annot->next)
645				if (pdf_update_annot(ctx, annot))
646					changed = 1;
647			for (widget = page->widgets; widget; widget = widget->next)
648				if (pdf_update_annot(ctx, widget))
649					changed = 1;
650	
651			pdf_end_operation(ctx, page->doc);
652		}
653		fz_catch(ctx)
654		{
655			pdf_abandon_operation(ctx, page->doc);
656			fz_rethrow(ctx);
657		}
658	
659		return changed;
